+T_DjiReturnCode
+Osal_TaskCreate(const char *name, void *(*taskFunc)(void *), uint32_t stackSize,
+                void *arg, T_DjiTaskHandle *task)
+{
+  int result;
+  char nameDealed[16] = {0};
+
+  *task = malloc(sizeof(pthread_t));
+  if (*task == NULL)
+  {
+    return DJI_ERROR_SYSTEM_MODULE_CODE_MEMORY_ALLOC_FAILED;
+  }
+
+  result = pthread_create(*task, NULL, taskFunc, arg);
+  if (result != 0)
+  {
+    return DJI_ERROR_SYSTEM_MODULE_CODE_SYSTEM_ERROR;
+  }
+
+  if (name != NULL) strncpy(nameDealed, name, sizeof(nameDealed) - 1);
+  result = pthread_setname_np(*(pthread_t *)*task, nameDealed);
+  if (result != 0)
+  {
+    return DJI_ERROR_SYSTEM_MODULE_CODE_SYSTEM_ERROR;
+  }
+
+  pthread_setcanceltype(PTHREAD_CANCEL_ASYNCHRONOUS, NULL);
+  pthread_setcancelstate(PTHREAD_CANCEL_ENABLE, NULL);
+
+  return DJI_ERROR_SYSTEM_MODULE_CODE_SUCCESS;
+}
+
+T_DjiReturnCode
+Osal_TaskDestroy(T_DjiTaskHandle task)
+{
+  pthread_cancel(*(pthread_t *)task);
+  free(task);
+
+  return DJI_ERROR_SYSTEM_MODULE_CODE_SUCCESS;
+}
+
+T_DjiReturnCode
+Osal_TaskSleepMs(uint32_t timeMs)
+{
+  usleep(1000 * timeMs);
+
+  return DJI_ERROR_SYSTEM_MODULE_CODE_SUCCESS;
+}
