+ * @brief Wait the semaphore until token becomes available.
+ * @param semaphore: pointer to the created semaphore ID.
+ * @return an enum that represents a status of PSDK
+ */
+T_DjiReturnCode
+Osal_SemaphoreWait(T_DjiSemaHandle semaphore)
+{
+  int result;
