+  rc_msg.axes[3] = rc_data->throttle;  // [-10000,10000]
+  rc_msg.buttons[0] = rc_data->mode;   // [-10000,10000]
+  rc_msg.buttons[1] = rc_data->gear;   // [-10000,10000]
+  rc_pub_->publish(rc_msg);
+  return DJI_ERROR_SYSTEM_MODULE_CODE_SUCCESS;
