+
+  return_code = DjiPlatform_RegOsalHandler(&osal_handler);
+  if (return_code != DJI_ERROR_SYSTEM_MODULE_CODE_SUCCESS)
+  {
+    RCLCPP_ERROR(get_logger(),
+                 "Register OSAL handler error. Error code is: %ld",
