+    return false;
+  }
+  RCLCPP_INFO(get_logger(), "Registered HAL handler");
+
+#if (HARDWARE_CONNECTION == DJI_USE_UART_AND_USB_BULK_DEVICE)
+  RCLCPP_INFO(get_logger(), "Using DJI_USE_UART_AND_USB_BULK_DEVICE");
